# FullCalendar React Setup

```jsx
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';

export default function Calendar() {
  const handleDateClick = (arg) => {
    alert(arg.dateStr);
  };

  return (
    <FullCalendar
      plugins={[dayGridPlugin, interactionPlugin]}
      dateClick={handleDateClick}
    />
  );
}
```

Packages: @fullcalendar/react, @fullcalendar/core, @fullcalendar/daygrid, @fullcalendar/timegrid, @fullcalendar/interaction.

**Category:** Getting Started
**URL:** https://fullcalendar.io/docs/react

# Multi-Plugin Initialization

```javascript
import { Calendar } from '@fullcalendar/core';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import listPlugin from '@fullcalendar/list';

let calendar = new Calendar(calendarEl, {
  plugins: [dayGridPlugin, timeGridPlugin, listPlugin],
  initialView: 'dayGridMonth',
  headerToolbar: {
    left: 'prev,next today',
    center: 'title',
    right: 'dayGridMonth,timeGridWeek,listWeek'
  }
});
calendar.render();
```

Views: dayGridMonth, dayGridWeek, dayGridDay, timeGridWeek, timeGridDay, listWeek, listMonth.

**Category:** Configuration
**URL:** https://fullcalendar.io/docs/initialize-es6

# External Drag and Drop

Enable dragging external events onto the calendar.

```javascript
var calendar = new Calendar(calendarEl, {
  headerToolbar: {
    left: 'prev,next today',
    center: 'title',
    right: 'dayGridMonth,timeGridWeek,timeGridDay'
  },
  editable: true,
  droppable: true,
  drop: function(info) {
    if (checkbox.checked) {
      info.draggedEl.parentNode.removeChild(info.draggedEl);
    }
  }
});
```

Requires: interactionPlugin.
Props: editable (drag/resize events), droppable (accept external drops), drop (callback on drop).

**Category:** Features
**URL:** https://fullcalendar.io/docs/external-dragging

# Event Object and Sources

Event object properties:
```typescript
interface EventInput {
  id?: string;
  title: string;
  start: Date | string;
  end?: Date | string;
  allDay?: boolean;
  color?: string;
  backgroundColor?: string;
  borderColor?: string;
  textColor?: string;
  url?: string;
  extendedProps?: Record<string, any>;
  editable?: boolean;
  display?: 'auto' | 'block' | 'list-item' | 'background' | 'inverse-background' | 'none';
}
```

Event sources:
```jsx
<FullCalendar
  events={[
    { title: 'Event 1', start: '2026-01-01' },
    { title: 'Event 2', start: '2026-01-05', end: '2026-01-07' },
  ]}
/>

// Or from URL
<FullCalendar
  events="/api/events"
/>

// Or function
<FullCalendar
  events={(info, successCallback, failureCallback) => {
    fetch(`/api/events?start=${info.startStr}&end=${info.endStr}`)
      .then(res => res.json())
      .then(successCallback)
      .catch(failureCallback);
  }}
/>
```

**Category:** Data
**URL:** https://fullcalendar.io/docs/event-object

# Resource Timeline Views

```javascript
import {Calendar} from '@fullcalendar/core';
import resourceTimelinePlugin from '@fullcalendar/resource-timeline';
import interactionPlugin from '@fullcalendar/interaction';
const calendar = new Calendar(calendarEl, {
  plugins: [resourceTimelinePlugin, interactionPlugin],
  initialView: 'resourceTimelineDay',
  headerToolbar: {left:'prev,next', center:'title', right:'resourceTimelineDay,resourceTimelineWeek,resourceTimelineMonth'},
  editable: true,
  resourceAreaHeaderContent: 'Rooms',
  resources: [{id:'a',title:'Room A'},{id:'b',title:'Room B',eventColor:'green'}],
  events: '/api/events.json'
});
```

# Date Selection

```javascript
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
const calendar = new Calendar(calendarEl, {
  plugins: [interactionPlugin, dayGridPlugin, timeGridPlugin],
  selectable: true, selectMirror: true, editable: true,
  select: function(selectionInfo) {
    let title = prompt('Event title:');
    if (title) {
      calendar.addEvent({title, start: selectionInfo.start, end: selectionInfo.end, allDay: selectionInfo.allDay});
    }
    calendar.unselect();
  },
  dateClick: function(info) { console.log('Clicked date:', info.dateStr); }
});
```

# Event Data Transform

```javascript
eventDataTransform: function(eventData) {
  return {
    title: eventData.name || eventData.title,
    start: eventData.start_date || eventData.start,
    end: eventData.end_date || eventData.end,
    color: eventData.category === 'meeting' ? 'blue' : 'green',
    extendedProps: {description: eventData.description}
  };
}
```
Receives raw event data from JSON feeds, returns FullCalendar Event object or false to discard.

# Event Sources

Event source types:
```javascript
// 1. JSON Feed (auto-fetches with date range params)
{url: '/api/events', color: 'yellow', textColor: 'black'}
// 2. Function (custom fetching logic)
{events: function(fetchInfo, successCallback, failureCallback) {
  fetch(`/api/events?start=${fetchInfo.startStr}&end=${fetchInfo.endStr}`)
    .then(res => res.json()).then(data => successCallback(data));
}}
// 3. Array (static)
{events: [{title:'Event 1',start:'2026-02-10'},{title:'Event 2',start:'2026-02-12'}]}
// 4. Google Calendar
{googleCalendarId: 'abcd1234@group.calendar.google.com'}
```
JSON feeds automatically receive start, end, timeZone params.

# Vertical Resource View

```javascript
import resourceDayGridPlugin from '@fullcalendar/resource-daygrid';
import resourceTimeGridPlugin from '@fullcalendar/resource-timegrid';
const calendar = new Calendar(calendarEl, {
  plugins: [interactionPlugin, resourceDayGridPlugin, resourceTimeGridPlugin],
  initialView: 'resourceTimeGridDay',
  headerToolbar: {right: 'resourceTimeGridDay,resourceTimeGridTwoDay,timeGridWeek,dayGridMonth'},
  views: {
    resourceTimeGridTwoDay: {type:'resourceTimeGrid', duration:{days:2}, buttonText:'2 days'}
  },
  resources: [{id:'a',title:'Room A'},{id:'b',title:'Room B',eventColor:'green'}],
  editable: true, selectable: true
});
```
Custom views: define type, duration, and buttonText. Resources appear as columns.
